     3â†’
     4â†’interface AudioVisualizerProps {
     5â†’    audioData: Uint8Array;
     6â†’    state: 'idle' | 'listening' | 'processing' | 'error';
     7â†’}
     8â†’
     9â†’/**
    10â†’ * Circular audio visualizer component
    11â†’ */
    12â†’export function AudioVisualizer({ audioData, state }: AudioVisualizerProps) {
    13â†’    const canvasRef = useRef<HTMLCanvasElement>(null);
    14â†’
    15â†’    useEffect(() => {
    16â†’        const canvas = canvasRef.current;
    17â†’        if (!canvas) return;
    18â†’
    19â†’        const ctx = canvas.getContext('2d');
    20â†’        if (!ctx) return;
    21â†’
    22â†’        // Set canvas size
    23â†’        const size = 200;
    24â†’        canvas.width = size;
    25â†’        canvas.height = size;
    26â†’
    27â†’        const centerX = size / 2;
    28â†’        const centerY = size / 2;
    29â†’        const radius = 60;
    30â†’
    31â†’        // Clear canvas
    32â†’        ctx.clearRect(0, 0, size, size);
    33â†’
    34â†’        if (state === 'idle') {
    35â†’            // Draw idle state: simple pulsing dot
    36â†’            drawIdleState(ctx, centerX, centerY, radius);
    37â†’        } else if (state === 'listening') {
    38â†’            // Draw listening state: circular waveform
    39â†’            drawWaveform(ctx, centerX, centerY, radius, audioData);
    40â†’        } else if (state === 'processing') {
    41â†’            // Draw processing state: spinning loader
    42â†’            drawProcessing(ctx, centerX, centerY, radius);
    43â†’        } else if (state === 'error') {
    44â†’            // Draw error state: red pulsing
    45â†’            drawError(ctx, centerX, centerY, radius);
    46â†’        }
    47â†’    }, [audioData, state]);
    48â†’
    49â†’    return <canvas ref={canvasRef} className="audio-visualizer" />;
    50â†’}
    51â†’
    52â†’/**
    53â†’ * Draw idle state
    54â†’ */
    55â†’function drawIdleState(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
    56â†’    const time = Date.now() / 1000;
    57â†’    const pulseScale = 1 + Math.sin(time * 2) * 0.1;
    58â†’
    59â†’    ctx.beginPath();
    60â†’    ctx.arc(x, y, radius * 0.3 * pulseScale, 0, Math.PI * 2);
    61â†’    ctx.fillStyle = 'rgba(0, 217, 255, 0.3)';
    62â†’    ctx.fill();
    63â†’
    64â†’    // Glow
    65â†’    ctx.shadowBlur = 20;
    66â†’    ctx.shadowColor = '#00d9ff';
    67â†’}
    68â†’
    69â†’/**
    70â†’ * Draw circular waveform
    71â†’ */
    72â†’function drawWaveform(
    73â†’    ctx: CanvasRenderingContext2D,
    74â†’    x: number,
    75â†’    y: number,
    76â†’    radius: number,
    77â†’    audioData: Uint8Array
    78â†’) {
    79â†’    const bars = 64; // Number of bars around the circle
    80â†’    const barWidth = 3;
    81â†’    const gap = 2;
    82â†’
    83â†’    for (let i = 0; i < bars; i++) {
    84â†’        const dataIndex = Math.floor((i / bars) * audioData.length);
    85â†’        const amplitude = audioData[dataIndex] / 255; // Normalize to 0-1
    86â†’
    87â†’        const angle = (i / bars) * Math.PI * 2 - Math.PI / 2;
    88â†’        const barHeight = amplitude * 40 + 5;
    89â†’
    90â†’        const x1 = x + Math.cos(angle) * radius;
    91â†’        const y1 = y + Math.sin(angle) * radius;
    92â†’        const x2 = x + Math.cos(angle) * (radius + barHeight);
    93â†’        const y2 = y + Math.sin(angle) * (radius + barHeight);
    94â†’
    95â†’        ctx.beginPath();
    96â†’        ctx.moveTo(x1, y1);
    97â†’        ctx.lineTo(x2, y2);
    98â†’        ctx.lineWidth = barWidth;
    99â†’        ctx.strokeStyle = `rgba(0, 217, 255, ${0.5 + amplitude * 0.5})`;
   100â†’        ctx.shadowBlur = 10;
   101â†’        ctx.shadowColor = '#00d9ff';
   102â†’        ctx.stroke();
   103â†’    }
   104â†’
   105â†’    // Center circle
   106â†’    ctx.beginPath();
   107â†’    ctx.arc(x, y, radius * 0.6, 0, Math.PI * 2);
   108â†’    ctx.fillStyle = 'rgba(10, 10, 15, 0.8)';
   109â†’    ctx.fill();
   110â†’}
   111â†’
   112â†’/**
   113â†’ * Draw processing spinner
   114â†’ */
   115â†’function drawProcessing(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
   116â†’    const time = Date.now() / 1000;
   117â†’    const rotation = time * 2; // Speed of rotation
   118â†’
   119â†’    for (let i = 0; i < 12; i++) {
   120â†’        const angle = (i / 12) * Math.PI * 2 + rotation;
   121â†’        const opacity = (i / 12);
   122â†’
   123â†’        const x1 = x + Math.cos(angle) * radius * 0.6;
   124â†’        const y1 = y + Math.sin(angle) * radius * 0.6;
   125â†’        const x2 = x + Math.cos(angle) * radius;
   126â†’        const y2 = y + Math.sin(angle) * radius;
   127â†’
   128â†’        ctx.beginPath();
   129â†’        ctx.moveTo(x1, y1);
   130â†’        ctx.lineTo(x2, y2);
   131â†’        ctx.lineWidth = 3;
   132â†’        ctx.strokeStyle = `rgba(0, 217, 255, ${opacity})`;
   133â†’        ctx.stroke();
   134â†’    }
   135â†’}
   136â†’
   137â†’/**
   138â†’ * Draw error state
   139â†’ */
   140â†’function drawError(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
   141â†’    const time = Date.now() / 1000;
   142â†’    const pulseScale = 1 + Math.sin(time * 4) * 0.15;
   143â†’
   144â†’    // Outer pulse
   145â†’    ctx.beginPath();
   146â†’    ctx.arc(x, y, radius * pulseScale, 0, Math.PI * 2);
   147â†’    ctx.strokeStyle = 'rgba(255, 71, 87, 0.6)';
   148â†’    ctx.lineWidth = 3;
   149â†’    ctx.shadowBlur = 20;
   150â†’    ctx.shadowColor = '#ff4757';
   151â†’    ctx.stroke();
   152â†’
   153â†’    // Inner circle
   154â†’    ctx.beginPath();
   155â†’    ctx.arc(x, y, radius * 0.5, 0, Math.PI * 2);
   156â†’    ctx.fillStyle = 'rgba(255, 71, 87, 0.3)';
   157â†’    ctx.fill();
   158â†’}
