    40â†’                    sampleRate: AUDIO_SAMPLE_RATE,
    41â†’                    echoCancellation: true,
    42â†’                    noiseSuppression: true,
    43â†’                    autoGainControl: true,
    44â†’                },
    45â†’            });
    46â†’
