    70â†’                    const sample = Math.max(-1, Math.min(1, inputData[i]));
    71â†’                    pcmBuffer[i] = sample < 0 ? sample * 0x8000 : sample * 0x7FFF;
    72â†’                }
    73â†’
    74â†’                if (this.onPcmChunk) {
    75â†’                    this.onPcmChunk(pcmBuffer.buffer as ArrayBuffer);
    76â†’                }
